import java.beans.PropertyVetoException;
import java.util.Hashtable;
import java.util.Map;
import javax.naming.Context;
import javax.naming.NamingException;
import javax.naming.directory.DirContext;
import javax.naming.directory.InitialDirContext;
import javax.naming.ldap.LdapName;

public class LdapUserSearch {

    public static Map<String, Object> searchUserByUsername(String username, String ldapUrl, String userDn, String password) throws NamingException, PropertyVetoException {
        Hashtable<String, String> env = new Hashtable<>();
        env.put(Context.INITIAL_CONTEXT_FACTORY, "com.sun.jndi.ldap.LdapCtxFactory");
        env.put(Context.PROVIDER_URL, ldapUrl);
        env.put(Context.SECURITY_AUTHENTICATION, "simple");
        env.put(Context.SECURITY_PRINCIPAL, userDn);
        env.put(Context.SECURITY_CREDENTIALS, password);

        DirContext ctx = (DirContext) new InitialDirContext(env);

        LdapName userNameLdapName = new LdapName("CN=" + username);
        Object userObj = ctx.search(userNameLdapName, "(objectClass=*)");

        if (userObj != null && userObj instanceof DirContext) {
            DirContext user = (DirContext) userObj;
            Map<String, Object> userAttributes = new Hashtable<>();
            for (String attribute : new String[]{"mail", "cn", "department"}) {
                Object attrValue = user.get(attribute);
                if (attrValue != null) {
                    userAttributes.put(attribute, attrValue);
                }
            }
            return userAttributes;
        }
        return null;
    }
}